const sd = $getWorkflowStaticData('global');
const cached = sd.googleAuth || {};
const now = Date.now();

if (cached.accessToken && cached.expiresAt && now < cached.expiresAt) {
  return [{ json: { ...$json, accessToken: cached.accessToken } }];
}

const clientId = $env.GOOGLE_CLIENT_ID;
const clientSecret = $env.GOOGLE_CLIENT_SECRET;
const refreshToken = $env.GOOGLE_REFRESH_TOKEN;

if (!clientId || !clientSecret || !refreshToken) {
  throw new Error('GOOGLE_CLIENT_ID, GOOGLE_CLIENT_SECRET, and GOOGLE_REFRESH_TOKEN must be set');
}

const response = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: 'client_id=' + encodeURIComponent(clientId) +
    '&client_secret=' + encodeURIComponent(clientSecret) +
    '&refresh_token=' + encodeURIComponent(refreshToken) +
    '&grant_type=refresh_token',
  timeout: 15000
});

sd.googleAuth = {
  accessToken: response.access_token,
  expiresAt: now + (response.expires_in - 100) * 1000
};

return [{ json: { ...$json, accessToken: response.access_token } }];
